{
  "summary": "This paper presents a comprehensive benchmark evaluating multiple continual learning methods across five pre-trained language models on three NLP classification datasets. It introduces a novel layer-wise probing technique to analyze representational forgetting and finds that experience replay methods outperform regularization-based approaches, with BERT being the most robust PLM. The study offers valuable insights into internal forgetting dynamics and sets directions for future research in PLM-tailored continual learning.",
  "strengths": [
    {
      "point": "Comprehensive empirical evaluation of multiple CL methods and PLMs",
      "evidence": "Evaluated 5 PLMs (BERT, ALBERT, RoBERTa, GPT2, XLNET) and 6 CL schemes on 3 diverse NLP datasets under Task-IL and Class-IL settings."
    },
    {
      "point": "Novel layer-wise probing method to analyze forgetting inside PLMs",
      "evidence": "Developed prototype-based layer-wise probing revealing that forgetting affects both classifier and middle layers, with replay methods better preserving representations."
    },
    {
      "point": "Insightful findings on the superiority of experience replay methods",
      "evidence": "Experience replay (ER, DERPP) consistently outperforms regularization (EWC) and dynamic architecture (HAT) methods in accuracy and backward transfer."
    },
    {
      "point": "Detailed analysis of PLM robustness and internal dynamics",
      "evidence": "BERT found most robust overall; layer-wise analysis shows varying robustness across layers and PLMs, highlighting fragile and stable components."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to recent PLM-specific continual learning methods",
      "evidence": "No baselines such as adapter-based CL, prompt-tuning, or parameter-efficient fine-tuning methods like LoRA or prefix-tuning included."
    },
    {
      "point": "Insufficient methodological justification and ablation studies",
      "evidence": "No explicit rationale for chosen CL methods and datasets; missing ablations on replay buffer size, sampling strategies, and memory management."
    },
    {
      "point": "Unclear adaptation and fairness in Class-IL evaluation",
      "evidence": "No description of how task-label-dependent methods like HAT are adapted or excluded in Class-IL, risking unfair comparisons."
    },
    {
      "point": "Limited evaluation metrics and missing statistical rigor",
      "evidence": "Only accuracy, FWT, and BWT reported; no per-task forgetting, calibration, robustness, or uncertainty metrics; no variance or significance testing."
    },
    {
      "point": "Reproducibility concerns due to missing hyperparameter and probing method details",
      "evidence": "Lack of hyperparameter tuning protocols, final values, and detailed description or validation of the prototype-based probing method."
    },
    {
      "point": "Limited scope in tasks, domains, and scalability considerations",
      "evidence": "Only classification tasks on English datasets evaluated; no cross-domain, cross-lingual, or large-scale PLM experiments; no discussion on task-agnostic or longer task sequences."
    }
  ],
  "questions": [
    {
      "question": "How do recent PLM-tailored continual learning methods compare to classical CL approaches?",
      "motivation": "Including adapter-based, prompt-tuning, or parameter-efficient fine-tuning methods could reveal more practical and efficient solutions."
    },
    {
      "question": "What is the impact of replay buffer size and sampling strategy on continual learning performance and scalability?",
      "motivation": "Understanding these factors is crucial for optimizing replay methods and ensuring their applicability in resource-constrained settings."
    },
    {
      "question": "How can forgetting in middle layers be effectively regularized or mitigated?",
      "motivation": "Layer-wise probing shows middle layers are fragile; targeted methods could improve overall CL robustness."
    },
    {
      "question": "How do task order and curriculum learning affect forgetting and transfer in PLM continual learning?",
      "motivation": "Task sequencing can influence CL outcomes; exploring this could guide better training protocols."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
